/* Offline minimal Markdown parser: window.marked.parse(md) */
(function(){
  'use strict';

  function escapeHtml(str){
    let s = String(str ?? '');
    s = s.replace(/&/g,'&amp;');
    s = s.replace(/</g,'&lt;');
    s = s.replace(/>/g,'&gt;');
    s = s.replace(/"/g,'&quot;');
    s = s.replace(/'/g,'&#39;');
    return s;
  }

  function inline(md){
    let s = escapeHtml(md);

    // images: ![alt](url)
    s = s.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, function(_, alt, url){
      return '<img src="' + url + '" alt="' + alt + '">';
    });

    // links: [text](url)
    s = s.replace(/\[([^\]]+)\]\(([^)]+)\)/g, function(_, text, url){
      return '<a href="' + url + '" target="_blank" rel="noopener">' + text + '</a>';
    });

    // inline code: `code`
    s = s.replace(/`([^`]+)`/g, function(_, code){
      return '<code>' + code + '</code>';
    });

    // bold: **text**
    s = s.replace(/\*\*([^*]+)\*\*/g, function(_, t){
      return '<strong>' + t + '</strong>';
    });

    // italic: *text*
    s = s.replace(/(^|[^*])\*([^*]+)\*/g, function(_, p1, t){
      return p1 + '<em>' + t + '</em>';
    });

    return s;
  }

  
  function splitTableRow(line){
    // Remove leading/trailing pipe for easier split
    let s = String(line ?? '').trim();
    if(s.startsWith('|')) s = s.slice(1);
    if(s.endsWith('|')) s = s.slice(0,-1);
    return s.split('|').map(c => c.trim());
  }

  function parseAlign(sepLine){
    // returns array of 'left'|'center'|'right'|'' for each column
    const cells = splitTableRow(sepLine);
    return cells.map(c => {
      const t = c.replace(/\s/g,'');
      const left = t.startsWith(':');
      const right = t.endsWith(':');
      if(left && right) return 'center';
      if(right) return 'right';
      if(left) return 'left';
      return '';
    });
  }

  function isTableSeparator(line){
    // e.g. |---|---:|:---:|
    const s = String(line ?? '').trim();
    if(!s.includes('|')) return false;
    // remove pipes and spaces, then validate each cell
    const cells = splitTableRow(s);
    if(cells.length < 2) return false;
    return cells.every(c => /^:?-{3,}:?$/.test(c.trim()));
  }

  function isTableHeader(line){
    const s = String(line ?? '').trim();
    if(!s.includes('|')) return false;
    const cells = splitTableRow(s);
    return cells.length >= 2 && cells.some(c => c.length > 0);
  }

  function renderTable(headerLine, sepLine, bodyLines){
    const headers = splitTableRow(headerLine);
    const aligns = parseAlign(sepLine);
    const colCount = Math.max(headers.length, aligns.length);

    function alignStyle(idx){
      const a = aligns[idx] || '';
      return a ? ' style="text-align:' + a + ';"' : '';
    }

    let out = '<table><thead><tr>';
    for(let c=0;c<colCount;c++){
      const text = headers[c] ?? '';
      out += '<th' + alignStyle(c) + '>' + inline(text) + '</th>';
    }
    out += '</tr></thead><tbody>';

    for(const line of bodyLines){
      const cells = splitTableRow(line);
      out += '<tr>';
      for(let c=0;c<colCount;c++){
        const text = cells[c] ?? '';
        out += '<td' + alignStyle(c) + '>' + inline(text) + '</td>';
      }
      out += '</tr>';
    }
    out += '</tbody></table>';
    return out;
  }

function parse(md){
    const lines = String(md ?? '').replace(/\r\n/g,'\n').replace(/\r/g,'\n').split('\n');
    let html = '';

    let inCode = false;
    let codeBuf = [];
    let inUl = false;
    let inOl = false;
    let inBlockquote = false;

    function closeLists(){
      if(inUl){ html += '</ul>'; inUl = false; }
      if(inOl){ html += '</ol>'; inOl = false; }
    }

    function closeBlockquote(){
      if(inBlockquote){ html += '</blockquote>'; inBlockquote = false; }
    }

    for(let i=0;i<lines.length;i++){
      const raw = lines[i];
      const line = raw;

      // GitHub-flavored markdown tables (relaxed)
      // Accept optional blank lines between header/separator/rows because
      // our teaching materials may insert blank lines for readability.
      // Detect: header line, then (after skipping blanks) separator line.
      if(!inCode && isTableHeader(line)){
        let k = i + 1;
        while(k < lines.length && (lines[k] ?? '').trim() === '') k++;
        if(k < lines.length && isTableSeparator(lines[k] || '')){
          closeLists();
          closeBlockquote();
          const headerLine = line;
          const sepLine = lines[k];
          const body = [];
          let j = k + 1;
          while(j < lines.length){
            const ln = lines[j] ?? '';
            const t = ln.trim();
            if(t === ''){ j++; continue; } // ignore blank lines inside table
            // stop if the next block starts (heading, list, quote, fence)
            if(t.startsWith('#') || t.startsWith('- ') || /^\d+\.\s/.test(t) || t.startsWith('>') || t.startsWith('```')) break;
            if(!ln.includes('|')) break;
            body.push(ln);
            j++;
          }
          html += renderTable(headerLine, sepLine, body);
          i = j - 1; // advance
          continue;
        }
      }


      // code fence
      if(line.trim().startsWith('```')){
        if(!inCode){
          closeLists();
          closeBlockquote();
          inCode = true;
          codeBuf = [];
        }else{
          inCode = false;
          html += '<pre><code>' + escapeHtml(codeBuf.join('\n')) + '</code></pre>';
        }
        continue;
      }

      if(inCode){
        codeBuf.push(raw);
        continue;
      }

      // blank line
      if(line.trim()===''){
        closeLists();
        closeBlockquote();
        continue;
      }

      // blockquote
      if(line.trim().startsWith('>')){
        closeLists();
        if(!inBlockquote){ html += '<blockquote>'; inBlockquote = true; }
        const body = line.trim().replace(/^>\s?/, '');
        html += '<div>' + inline(body) + '</div>';
        continue;
      }else{
        closeBlockquote();
      }

      // heading
      const h = line.match(/^(#{1,3})\s+(.*)$/);
      if(h){
        closeLists();
        const level = h[1].length;
        html += '<h' + level + '>' + inline(h[2]) + '</h' + level + '>';
        continue;
      }

      // horizontal rule
      if(/^---\s*$/.test(line.trim())){
        closeLists();
        html += '<hr>';
        continue;
      }

      // unordered list
      const ul = line.match(/^\s*[-*]\s+(.*)$/);
      if(ul){
        if(inOl){ html += '</ol>'; inOl = false; }
        if(!inUl){ html += '<ul>'; inUl = true; }
        html += '<li>' + inline(ul[1]) + '</li>';
        continue;
      }

      // ordered list
      const ol = line.match(/^\s*\d+\.\s+(.*)$/);
      if(ol){
        if(inUl){ html += '</ul>'; inUl = false; }
        if(!inOl){ html += '<ol>'; inOl = true; }
        html += '<li>' + inline(ol[1]) + '</li>';
        continue;
      }

      // paragraph
      closeLists();
      html += '<p>' + inline(line) + '</p>';
    }

    // cleanup
    if(inCode){
      html += '<pre><code>' + escapeHtml(codeBuf.join('\n')) + '</code></pre>';
    }
    closeLists();
    closeBlockquote();

    return html;
  }

  window.marked = window.marked || {};
  window.marked.parse = parse;
})();
